var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"어이, 뭘 하고 있나, 친구? 별이라도 세고 있는 거야?","JPN":"おい、何をしてるんだ？　星でも数えてるのか？","ENG":"Hey, what's up buddy? You counting the stars or something?","TWN":"喂，你在幹什麼啊，朋友？數星星？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"별은 위협적이지 않다. 수를 세는 일도 전술적으로 필요하지 않다.","JPN":"星は威嚇しない。数を数えるのも、戦術的に必要ない。","ENG":"The celestial bodies you call stars are not an immediate threat. Therefore, counting their quantity is tactically unnecessary.","TWN":"星星沒有威脅性。這種行為也沒有任何戰略意義。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L5_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"거, 재미없기는. 그럴 땐 이렇게 대답하는 거야.","JPN":"つまらないな。そういう時は、こういう風に答えるんだ。","ENG":"Ugh, how boring. This is how you ought to respond.","TWN":"唉，真無趣。我就知道你會這樣回答。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"박사의 연약한 단백질 하드웨어로 생각할 만한 하찮은 일이로군!","JPN":"いかにも博士の軟弱なタンパク質ハードウェアが考えそうなことだ！","ENG":"Only a frail creature comprised of protein-based hardware would think of such petty musings!","TWN":"但這就是博士會用他脆弱的蛋白質硬體思考的小事！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"나의 강인한 155mm 아틀라틀 포신과 메인 카메라는 언제나 침식체의 도발을 경계하고 있다네!","JPN":"吾輩の強靭な155mmアトラトル砲身とメインカメラは、常に侵食体の挑発を警戒している！","ENG":"My potent 155 mm Atlatl gun and main camera are always on the lookout for the provocation of Corrupted Objects!","TWN":"我強韌的155mm阿特拉托機槍炮和主相機隨時都在警戒著侵蝕體！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"어때, 이 정도는 되야 세기말 결전병기 느낌이 나지 않겠나.","JPN":"よし、これで世紀末決戦兵器らしくなった。","ENG":"Now that sounds more like a real Ultimate Doomsday Weapon., don't you think?","TWN":"怎麼樣？這樣說才有世紀末決戰兵器的感覺吧。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"의미를 알 수 없다.","JPN":"意味がわからない。","ENG":"That does not compute.","TWN":"意義不明。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"지금은 세기말도 아니고, 결전병기라는 분류체계는 존재하지 않는다.","JPN":"今は世紀末でもなく、決戦兵器という分類体系は存在しない。","ENG":"There is no weapon category called Ultimate, and the world is not currently facing Doomsday.","TWN":"現在不是世紀末，武器分類中也沒有決戰兵器。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"그건 그저 관용적인 표현일 뿐이다.","JPN":"それは単なる慣用的な表現だ。","ENG":"Your statement is riddled with inherent anachronisms merely for the sake of human romanticism.","TWN":"那只是一種慣用的表達方式。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"물론 그렇긴 하지.","JPN":"もちろん、そうだ。","ENG":"I suppose you're right.","TWN":"你說得沒錯。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"하지만 살다 보면 때로는 그런 관용적인 표현이 더 중요할 때가 있거든.","JPN":"だが、そういう慣用的な表現が大事な時もあるんだ。","ENG":"But then again, romance often becomes the most important part of life.","TWN":"不過，有時候這種表達方式很重要。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"뭐, 언젠가는 너도 깨닫게 될 거야.","JPN":"まあ、いつか君も気づくだろう。","ENG":"You'll see, one day.","TWN":"嗯，總有一天你也會明白的。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"네게 탑재된 인공지능 모듈은 경험이 쌓일수록 계속해서 진화해 나가는 시스템이라고, 엠버 소장이 말했으니까.","JPN":"君に搭載された人工知能モジュールは、\\n経験を重ねるごとに進化するシステムだと、アンバー所長が言っていたからな。","ENG":"Director Ember said the A.I. module in you continues to evolve with experience.","TWN":"琥珀所長說過，你所搭載的人工智慧模組會隨著經驗的積累不斷進化。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"엠버 소장이라면, 당신과 함께 나의 설계를 주도한 사람들 중 하나라고 메모리에 기록되어 있다.","JPN":"アンバー所長なら、教授と一緒に吾輩の設計を主導した人々の一人だと、メモリーに記録されている。","ENG":"Director Ember... My files indicate she was one of the main designers who contributed to my creation, along with you.","TWN":"琥珀所長，參照我的記憶體紀錄，她是和您一起參與設計我的主要人員之一。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하지만 첫 출격 이후 한 번도 만난 적이 없다. 그녀는 어디에 있는 거지?","JPN":"だが、初出撃以来、一度も会ったことがない。彼女はどこにいる？","ENG":"But I never encountered her after my initial deployment. Where is she?","TWN":"但在第一次出擊後，我就再也沒有見過她。她現在在哪？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"아, 그녀는...... 기밀 반출 혐의로 퓨처 앳 워 프로젝트에서 제명됐어.","JPN":"ああ、彼女は……機密漏洩の疑いで、フューチャーアットウォー・プロジェクトから除名された。","ENG":"Oh, you see... She was booted from the Future at War Project for the unauthorized disclosure of classified information.","TWN":"啊，她……因為洩露機密的嫌疑，被天啟兵器計畫除名了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"사람들을 구하기 위해서 어쩔 수 없는 일이었다고 탄원서를 제출했지만, 그놈의 정치적인 문제라는 게 복잡하게 얽혀 있어서 어쩔 수가 없더군.","JPN":"人を救うためには仕方なかったという嘆願書を提出したが、\\n政治的な問題ってやつが複雑で、どうにもならなかった。","ENG":"Although she submitted a justification saying she had no choice in order to save many lives, it all got political and complicated in the end.","TWN":"雖然她提出了請願書，說這是為了救人不得已而為之的事情，但因為那傢伙的政治問題很複雜，所以沒辦法。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"그 뒤로는 잠적이라도 했는지 연락이 닿질 않아. 어디서 뭘 하는지 원......","JPN":"その後、行方をくらませて連絡もつかなくなった。どこで何をしてるのか……","ENG":"I guess she decided that she didn't want to be found after that. I can't seem to get in touch with her. I wonder what she's been up to...","TWN":"之後可能是潛逃了吧，我連絡不到她，也不知道她正在哪裡做什麼……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"그런데 그건 왜 묻지? 엄마가 그립기라도 한 건가?","JPN":"ところで、なぜ彼女のことを聞いたんだ？　お母さんに会いたいのか？","ENG":"Anyway, why do you ask? Do you miss mommy?","TWN":"不過你問這個幹什麼？難道是想媽媽了？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"의사결정 소프트웨어가 해당 질문에 대한 답을 구하고 있다.","JPN":"意思決定ソフトウェアが、質問に対する答えを求めている。","ENG":"The decision-making software is computing the response to this question...","TWN":"決策軟體正在尋找該問題的答案。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"이유는...... 나도 잘 모르겠다.","JPN":"理由は……吾輩もわからない。","ENG":"The reason is... unknown. I failed to get an answer.","TWN":"理由是……我也不知道。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"인공지능에 감정이 싹트는 단계인 건가?","JPN":"人工知能に感情が生まれる段階か？","ENG":"Is this where the A.I. starts to develop emotions?","TWN":"難道是人工智慧開始擁有感情的前兆嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"정말 그 여자 말대로 진화라도 하고 있나 보군.","JPN":"あの女の言った通り、進化してるようだな。","ENG":"Maybe you really are evolving, like she said.","TWN":"看來真的如那女人所說，正在進化啊。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"좋아, 그럼 말이 나온 김에 더 끝내 주는 걸 보여 주지.","JPN":"よし、ついでにもっといい物を見せてやる。","ENG":"Alright, then. While we're at it, let me show you something even more awesome.","TWN":"很好，藉這個機會，我給你看個更厲害的。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"이거 보이나?","JPN":"これ、見えるか？","ENG":"See this?","TWN":"能看見這個嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"물론이다. 나의 영상 인식 시스템은 야간에도 문제없이 작동 된다.","JPN":"もちろんだ。吾輩の映像認識システムは、夜間でも作動する。","ENG":"Of course. My visual recognition system is capable of operating in the dark as well.","TWN":"當然可以。我的畫面識別系統在夜間也可以正常運作。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_22"},{"id":"L33_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"여기 이 애가 내 딸이다. 이름은 아나스타샤.","JPN":"この子が私の娘だ。名前は、アナスタシア。","ENG":"This kid here is my daughter. Her name's Anastasia.","TWN":"這是我女兒。名字叫安娜斯塔莎。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"지금은 그냥 칭얼거리는 것밖에 할 줄 모르지만, 언젠가는 날 넘어서는 천재 공학자가 될 예정이지.","JPN":"今はまだ泣いてばかりだが、いつか私を越える天才工学者になるはずだ。","ENG":"She's nothing but a whiny little baby right now, but she'll surpass me as a genius engineer one day.","TWN":"雖然現在只會哭鬧，但她總有一天會成為超越我的天才工學家。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"미래의 일은 알 수 없다. 그건 추정일 뿐이다.","JPN":"未来のことはわからない。それは単なる推定だ。","ENG":"No one can be certain of the future. You are merely speculating.","TWN":"未來是未知的，這只不過是推測。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"맞아. 하지만 미래가 있다는 게 중요한 거야.","JPN":"ああ。だが、未来があるというのが大事なんだ。","ENG":"You're right. But the important thing is that we have a future we can speculate.","TWN":"沒錯。不過，重要的是能夠擁有未來。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"네가 우리에게 미래를 가져다 줬어.","JPN":"君は私たちに未来を与えてくれた。","ENG":"You brought us that future.","TWN":"你給我們帶來了未來。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"내가? 문장의 논리구조를 파악하기 힘들다.","JPN":"吾輩が？　文章の論理構造が把握できない。","ENG":"Me? Your sentence is too abstruse to deduce the reasoning.","TWN":"我？無法理解語句的邏輯結構。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"네가 그날 출격해 준 덕분에...... 내 딸아이를 비롯해서 많은 사람들이 계속 미래를 꿈꿀 수 있게 됐어.","JPN":"あの日、君が出撃してくれたおかげで……\\n私の娘をはじめとする多くの人々が、今も未来を描き続けている。","ENG":"Because you were deployed that day, many people, including my daughter, can look forward to the future.","TWN":"因為你那天的出擊……包括我女兒在內，很多人都得以擁有未來。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"너에겐 정말 감사하고 있다. 그리고 이런 황당한 프로젝트에 날 끌어들인 엠버 소장에게도.","JPN":"君には感謝している。あと、この迷プロジェクトに私を引きずり込んだ、アンバー所長にも。","ENG":"I'm very grateful to you for that. And to Director Ember, for dragging me into this ridiculous project.","TWN":"我真的很感謝你。我也很感激把我拉進這個荒唐計畫的琥珀所長。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"누군가는 너를 그저 무서운 괴물 병기라고만 생각할 수도 있겠지만......","JPN":"君のことを、恐ろしい怪物兵器だという思う人もいるかもしれない。","ENG":"Although some may see you as just an intimidating killing machine...","TWN":"可能會有人認為你只是個可怕的武器……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"적어도 널 설계한 우리들은 네가 사람들을 지키기 위해 태어났다는 걸 알고 있어.","JPN":"だが、少なくとも君を設計した私たちは、君が人を守るために生まれたことを知っている。","ENG":"your designers, at the very least, know that you were created to protect people.","TWN":"但至少你的設計者，至少我們知道你是為了保護人們而誕生的。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"그것만은 기억해 주길 바란다.","JPN":"それだけは覚えておいてくれ。","ENG":"I hope you'll remember that.","TWN":"希望你能記住這一點。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"접수했다.","JPN":"受け付けた。","ENG":"Acknowledged.","TWN":"收到。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};